    // ==========================================
    // CORE TRAVEL HELPERS (also used by audit tool)
    // ==========================================

    // Helper function to get travel time between two cities
    function getTravelTime(cityA, cityB) {
        const preferred = travelTimesSupplemental.find(route =>
            (route.from === cityA && route.to === cityB) ||
            (route.from === cityB && route.to === cityA)
        );
        if (preferred) return preferred;

        for (const category in travelTimes) {
            const routes = travelTimes[category];
            const found = routes.find(route => 
                (route.from === cityA && route.to === cityB) ||
                (route.from === cityB && route.to === cityA)
            );
            if (found) return found;
        }
        return null;
    }

    function parseDurationToHours(input) {
        if (!input || typeof input !== 'string') return null;
        const raw = input.trim();
        if (!raw) return null;

        // For ranges like "1h 05m-1h 20m", take the first (fastest) value.
        const firstPart = raw.split('-')[0].trim();

        // Support "1.5h", "1h 30m", "45m", "2h" etc. Ignore extra text.
        const hMatch = firstPart.match(/(\d+(?:\.\d+)?)\s*h/i);
        const mMatch = firstPart.match(/(\d+)\s*m/i);

        const hours = hMatch ? parseFloat(hMatch[1]) : 0;
        const mins = mMatch ? parseInt(mMatch[1], 10) : 0;

        const total = hours + mins / 60;
        return Number.isFinite(total) && total > 0 ? total : null;
    }

    function detectModeFromText(text) {
        const t = (text || '').toLowerCase();
        if (t.includes('ferry') || t.includes('ship')) return 'ferry';
        if (t.includes('train')) return 'train';
        if (t.includes('flight') || t.includes('air')) return 'flight';
        if (t.includes('bus')) return 'bus';
        return 'route';
    }

    function getLegOptions(from, to) {
        const out = [];

        const info = getTravelTime(from, to);
        if (info) {
            if (info.flight) {
                out.push({
                    mode: 'flight',
                    label: info.flight,
                    hours: (typeof info.flightHours === 'number' ? info.flightHours : parseDurationToHours(info.flight))
                });
            }
            if (info.train) {
                out.push({
                    mode: 'train',
                    label: info.train,
                    hours: (typeof info.trainHours === 'number' ? info.trainHours : parseDurationToHours(info.train))
                });
            }
        }

        const legKey = `${from}-${to}`;
        const legKeyReverse = `${to}-${from}`;
        const legLabel = legDurations[legKey] || legDurations[legKeyReverse];
        if (legLabel) {
            const mode = detectModeFromText(legLabel);
            const hours = parseDurationToHours(legLabel);
            const alreadyHasMode = out.some(o => o.mode === mode);
            if (!alreadyHasMode) {
                out.push({ mode, label: legLabel, hours });
            }
        }

        return out;
    }

    function getFastestLegOption(from, to) {
        const opts = getLegOptions(from, to).filter(o => typeof o.hours === 'number' && Number.isFinite(o.hours));
        if (opts.length === 0) return null;
        return opts.reduce((best, cur) => (cur.hours < best.hours ? cur : best));
    }

if (typeof module !== "undefined") module.exports = { cities, travelTimes, travelTimesSupplemental, legDurations, getTravelTime, getLegOptions, getFastestLegOption, parseDurationToHours };
